import React, { useState, useEffect } from "react";
import { useNavigate } from "react-router-dom";
import { FaComments, FaUserCircle } from "react-icons/fa";
import InicioSesion from "./inicioSesion";
import axios from "axios";

function Header({ loggedInUser, onLogout, onLogin }) {
  const navigate = useNavigate();
  const [loggedIn, setLoggedIn] = useState(false);
  const [menuOpen, setMenuOpen] = useState(false);
  const [showLogin, setShowLogin] = useState(false);

  useEffect(() => {
    const checkLoginStatus = () => {
      setLoggedIn(localStorage.getItem("loggedIn") === "true");
    };

    checkLoginStatus();
    window.addEventListener("storage", checkLoginStatus);
    return () => window.removeEventListener("storage", checkLoginStatus);
  }, []);

  const handleLoginClick = () => setShowLogin(true);

  const handleLoginSuccess = async ({ usuario, contrasena }) => {
    try {
      const res = await axios.post("http://localhost:3000/usuarios/login", {
        usuario,
        contrasenia: contrasena,
      });

      if (res.data && res.data.encontrado === 1) {
        localStorage.setItem("loggedIn", "true");
        localStorage.setItem("userInfo", JSON.stringify(res.data.usuario));
        setLoggedIn(true);
        setShowLogin(false);
      } else {
        alert("Credenciales incorrectas");
      }
    } catch (error) {
      console.error("Error en login:", error);
      alert("Error al iniciar sesión");
    }
  };

  const handleCloseLogin = () => setShowLogin(false);

  const handleUserClick = () => setMenuOpen((prev) => !prev);

  const handleLogout = () => {
    localStorage.removeItem("loggedIn");
    localStorage.removeItem("userInfo");
    setLoggedIn(false);
    setMenuOpen(false);
    navigate("/");
  };

  const styles = {
    header: {
      width: "100%",
      display: "flex",
      justifyContent: "space-between",
      alignItems: "center",
      padding: "1rem 2.5rem",
      backgroundColor: "white",
      position: "relative",
      zIndex: 50,
    },
    icon: {
      color: "black",
      cursor: "pointer",
    },
    logo: {
      height: "64px",
      objectFit: "contain",
    },
    dropdown: {
      position: "absolute",
      top: "80px",
      right: "40px",
      backgroundColor: "white",
      border: "1px solid #e2e2e2",
      borderRadius: "8px",
      boxShadow: "0 2px 6px rgba(0,0,0,0.2)",
      zIndex: 99,
    },
    dropdownItem: {
      padding: "10px 16px",
      width: "200px",
      textAlign: "left",
      cursor: "pointer",
      backgroundColor: "white",
      borderBottom: "1px solid #eee",
    },
  };

  return (
    <>
      <header className="fixed top-0 left-0 right-0 z-50 bg-white/95 backdrop-blur-sm border-b border-gray-100">
        <div className="max-w-7xl mx-auto px-6 py-4">
          <div className="flex justify-between items-center">
            {/* Logo/Título mejorado */}
            <h1 className="text-2xl font-serif text-brand-dark font-normal tracking-wide">
              Orbis Empresarial
            </h1>

            {/* Información del usuario o botón de login */}
            <div className="flex items-center space-x-4">
              {loggedInUser ? (
                <div className="flex items-center space-x-3">
                  <span className="text-sm font-medium text-brand-dark font-sans">
                    {loggedInUser.nombre}
                  </span>
                  <button
                    onClick={onLogout}
                    className="px-4 py-2 text-sm font-medium text-brand-slate hover:text-brand-dark border border-gray-200 rounded-md hover:bg-gray-50 transition-all duration-200 font-sans"
                  >
                    Cerrar Sesión
                  </button>
                </div>
              ) : (
                <button
                  onClick={onLogin}
                  className="px-4 py-2 bg-brand-dark text-white text-sm font-medium rounded-md hover:bg-brand-slate transition-all duration-200 font-sans"
                >
                  Iniciar Sesión
                </button>
              )}
            </div>
          </div>
        </div>
      </header>

      {showLogin && (
        <InicioSesion onLogin={handleLoginSuccess} onClose={handleCloseLogin} />
      )}
    </>
  );
};

export default Header;
